package ru.memearena.tournament.api; import org.springframework.context.annotation.Profile; import org.springframework.web.bind.annotation.*; import ru.memearena.tournament.application.*; import ru.memearena.tournament.infrastructure.*; import java.time.*; import java.util.*; @RestController @RequestMapping("/api/v1/admin/tournaments") public class AdminTournamentController{ private final TournamentCreationService creation; private final TournamentProgressionService progression; public AdminTournamentController(TournamentCreationService c,TournamentProgressionService p){creation=c;progression=p;} @PostMapping("/create") public Object create(){return creation.createToday();} @PostMapping("/{id}/advance") public Object advance(@PathVariable UUID id){return progression.advance(id);} }
